                return bytesCopied;
            }
            
            // Allocates and returns a new byte array
            public byte[] GetUnderlyingBytes()
            {
                const int sizeOfLengthField = 2;
                int limit = _parentMessage.Limit;
                _buffer.CheckLimit(limit + sizeOfLengthField);
                int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
                byte[] data = new byte[dataLength];
                _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
                _buffer.GetBytes(limit + sizeOfLengthField, data);

                return data;
            }

            public int SetUnderlying(byte[] src, int srcOffset, int length) =>
                SetUnderlying(new ReadOnlySpan<byte>(src, srcOffset, length));

            public int SetUnderlying(ReadOnlySpan<byte> src)
            {
                const int sizeOfLengthField = 2;
                int limit = _parentMessage.Limit;
                _parentMessage.Limit = limit + sizeOfLengthField + src.Length;
                _buffer.Uint16PutLittleEndian(limit, (ushort)src.Length);
                _buffer.SetBytes(limit + sizeOfLengthField, src);

                return src.Length;
            }

            public string GetUnderlying()
            {
                const int sizeOfLengthField = 2;
                int limit = _parentMessage.Limit;
                _buffer.CheckLimit(limit + sizeOfLengthField);
                int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
                _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
                return _buffer.GetStringFromBytes(UnderlyingResolvedCharacterEncoding, limit + sizeOfLengthField, dataLength);
            }

            public void SetUnderlying(string value)
            {
                var encoding = UnderlyingResolvedCharacterEncoding;
                const int sizeOfLengthField = 2;
                int limit = _parentMessage.Limit;
                int byteCount = encoding.GetByteCount(value);

                _parentMessage.Limit = limit + sizeOfLengthField + byteCount;

                _buffer.SetBytesFromString(encoding, value, limit + sizeOfLengthField);
                _buffer.Uint16PutLittleEndian(limit, (ushort)byteCount);
            }

                internal void BuildString(StringBuilder builder)
                {
                    if (_buffer == null)
                    {
                        return;
                    }

                    builder.Append('(');
                    builder.Append("Id=");
                    builder.Append(this.Id);
                    builder.Append('|');
                    builder.Append("IsFirm=");
                    builder.Append(this.IsFirm);
                    builder.Append('|');
                    builder.Append("IsCopyCat=");
                    builder.Append(this.IsCopyCat);
                    builder.Append('|');
                    builder.Append("Quantity=");
                    builder.Append(this.Quantity);
                    builder.Append('|');
                    builder.Append("BaseStrategy=");
                    builder.Append(this.BaseStrategy);
                    builder.Append('|');
                    builder.Append("Side=");
                    builder.Append(this.Side);
                    builder.Append('|');
                    builder.Append("Price=");
                    builder.Append(this.Price);
                    builder.Append('|');
                    builder.Append("Bid=");
                    builder.Append(this.Bid);
                    builder.Append('|');
                    builder.Append("Ask=");
                    builder.Append(this.Ask);
                    builder.Append('|');
                    builder.Append("Delta=");
                    builder.Append(this.Delta);
                    builder.Append('|');
                    builder.Append("TradeTime=");
                    builder.Append(this.TradeTime);
                    builder.Append('|');
                    builder.Append("Exchange=");
                    builder.Append("'");
                    for (int i = 0; i < ExchangeLength && this.GetExchange(i) > 0; ++i)
                    {
                        builder.Append((char)this.GetExchange(i));
                    }
                    builder.Append("'");
                    builder.Append('|');
                    builder.Append("Description=");
                    builder.Append('\'').Append(GetDescription()).Append('\'');
                    builder.Append('|');
                    builder.Append("Underlying=");
                    builder.Append('\'').Append(GetUnderlying()).Append('\'');
                    builder.Append(')');

                }
        }

        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new TradeFeedMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[TradeFeedMessage](sbeTemplateId=");
            builder.Append(TradeFeedMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(TradeFeedMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != TradeFeedMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(TradeFeedMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != TradeFeedMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(TradeFeedMessage.BlockLength);
            builder.Append("):");

            builder.Append("Id=");
            builder.Append(this.Id);
            builder.Append('|');
            builder.Append("IsLast=");
            builder.Append(this.IsLast);
            builder.Append('|');
            builder.Append("Trades=[");
            var trades = this.Trades;
            if (trades.Count > 0)
            {
                var first = true;
                while (trades.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    trades.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
    }
